/* ============================================
 Coordinating Processes/Threads in C
 Using POSIX Threads (pthread)
 ============================================ */

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>
#include <string.h>

#define NUM_THREADS 5
#define ITERATIONS 1000

/* ============================================
 Example 1: Critical Section with Mutex
 ============================================
*/
typedef struct {
 int counter;
 pthread_mutex_t lock;
} SharedCounter;

void* worker_mutex(void* arg) {
 SharedCounter* sc = (SharedCounter*)arg;

 for (int i = 0; i < ITERATIONS; i++) {
 // Entry section: acquire lock
 pthread_mutex_lock(&sc->lock);

 // Critical section: read-modify-write
 int temp = sc->counter;
 // Simulate some processing time
 usleep(1); 
 sc->counter = temp + 1;

 // Exit section: release lock
 pthread_mutex_unlock(&sc->lock);

 // Remainder section: do other work
 }
 return NULL;
}

void demonstrate_mutex(void) {
 printf("=== Mutex Example ===\n");

 SharedCounter sc;
 sc.counter = 0;
 pthread_mutex_init(&sc.lock, NULL);

 pthread_t threads[NUM_THREADS];

 // Create worker threads
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_create(&threads[i], NULL, worker_mutex, &sc);
 }

 // Wait for all threads
 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 printf("Expected: %d, Actual: %d\n", 
 NUM_THREADS * ITERATIONS, sc.counter);
 printf("Correct: %s\n\n", 
 sc.counter == NUM_THREADS * ITERATIONS ? "YES" : "NO - Race condition!");

 pthread_mutex_destroy(&sc.lock);
}

/* ============================================
 Example 2: Binary Semaphore using Mutex + Condition
 ============================================
*/
typedef struct {
 sem_t semaphore; // POSIX unnamed semaphore
 int thread_id;
 char* message;
} BinarySemaphoreDemo;

void* binary_semaphore_worker(void* arg) {
 BinarySemaphoreDemo* demo = (BinarySemaphoreDemo*)arg;

 // P operation (wait) - acquire
 sem_wait(&demo->semaphore);

 printf("Thread %d entered critical section\n", demo->thread_id);
 printf(" Message: %s\n", demo->message);

 sleep(1); // Simulate work in critical section

 printf("Thread %d exiting critical section\n", demo->thread_id);

 // V operation (signal) - release
 sem_post(&demo->semaphore);

 return NULL;
}

void demonstrate_binary_semaphore(void) {
 printf("=== Binary Semaphore Example ===\n");

 sem_t binary_sem;
 // Initialize to 1 (binary - allows one thread)
 sem_init(&binary_sem, 0, 1);

 pthread_t threads[3];
 BinarySemaphoreDemo demos[3];

 for (int i = 0; i < 3; i++) {
 demos[i].semaphore = binary_sem;
 demos[i].thread_id = i;
 demos[i].message = "Inside critical section";
 pthread_create(&threads[i], NULL, binary_semaphore_worker, &demos[i]);
 }

 for (int i = 0; i < 3; i++) {
 pthread_join(threads[i], NULL);
 }

 sem_destroy(&binary_sem);
 printf("Binary semaphore demo complete\n\n");
}

/* ============================================
 Example 3: Producer-Consumer with Counting Semaphores
 ============================================
*/
#define BUFFER_SIZE 5
#define NUM_ITEMS 10

typedef struct {
 int buffer[BUFFER_SIZE];
 int in; // Write index
 int out; // Read index

 // Counting semaphores
 sem_t empty_slots; // Count of empty slots
 sem_t full_slots; // Count of filled slots

 // Binary semaphore for mutual exclusion
 pthread_mutex_t mutex;
} BoundedBuffer;

void init_buffer(BoundedBuffer* buf) {
 buf->in = 0;
 buf->out = 0;

 // Initialize counting semaphores
 sem_init(&buf->empty_slots, 0, BUFFER_SIZE); // All slots empty
 sem_init(&buf->full_slots, 0, 0); // No items yet

 pthread_mutex_init(&buf->mutex, NULL);
}

void destroy_buffer(BoundedBuffer* buf) {
 sem_destroy(&buf->empty_slots);
 sem_destroy(&buf->full_slots);
 pthread_mutex_destroy(&buf->mutex);
}

void produce(BoundedBuffer* buf, int item) {
 // Wait for empty slot
 sem_wait(&buf->empty_slots);

 // Enter critical section
 pthread_mutex_lock(&buf->mutex);

 // Add item to buffer
 buf->buffer[buf->in] = item;
 printf("Produced: %d, buffer[in]=%d\n", item, buf->in);
 buf->in = (buf->in + 1) % BUFFER_SIZE;

 // Exit critical section
 pthread_mutex_unlock(&buf->mutex);

 // Signal that an item is available
 sem_post(&buf->full_slots);
}

int consume(BoundedBuffer* buf) {
 // Wait for item to be available
 sem_wait(&buf->full_slots);

 // Enter critical section
 pthread_mutex_lock(&buf->mutex);

 // Remove item from buffer
 int item = buf->buffer[buf->out];
 printf("Consumed: %d, buffer[out]=%d\n", item, buf->out);
 buf->out = (buf->out + 1) % BUFFER_SIZE;

 // Exit critical section
 pthread_mutex_unlock(&buf->mutex);

 // Signal that a slot is now empty
 sem_post(&buf->empty_slots);

 return item;
}

void* producer_thread(void* arg) {
 BoundedBuffer* buf = (BoundedBuffer*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 produce(buf, i * 100);
 usleep(rand() % 50000); // Random delay
 }
 return NULL;
}

void* consumer_thread(void* arg) {
 BoundedBuffer* buf = (BoundedBuffer*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 int item = consume(buf);
 usleep(rand() % 50000); // Random delay
 }
 return NULL;
}

void demonstrate_producer_consumer(void) {
 printf("\n=== Producer-Consumer Example ===\n");

 BoundedBuffer buf;
 init_buffer(&buf);

 pthread_t producer, consumer;

 pthread_create(&producer, NULL, producer_thread, &buf);
 pthread_create(&consumer, NULL, consumer_thread, &buf);

 pthread_join(producer, NULL);
 pthread_join(consumer, NULL);

 printf("Producer-Consumer demo complete\n");
 destroy_buffer(&buf);
}

/* ============================================
 Main Function
 ============================================
*/
int main(void) {
 printf("===========================================\n");
 printf("COORDINATING PROCESSES AND THREADS - C Demo\n");
 printf("===========================================\n\n");

 demonstrate_mutex();
 demonstrate_binary_semaphore();
 demonstrate_producer_consumer();

 return 0;
}

/* Compile with: gcc -o threads_demo threads_demo.c -lpthread -Wall
 Run: ./threads_demo */

import java.util.concurrent.ArrayBlockingQueue;
import java.util.concurrent.BlockingQueue;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Coordinating Processes and Threads in Java
 * Demonstrates monitor-based synchronization using synchronized keyword,
 * wait/notify, and Java's high-level concurrency utilities.
 */
public class ThreadCoordinationDemo {

 public static void main(String[] args) throws InterruptedException {
 System.out.println("========================================");
 System.out.println("COORDINATING PROCESSES AND THREADS - Java");
 System.out.println("========================================\n");

 // Run all demonstrations
 demonstrateCriticalSection();
 demonstrateBinarySemaphore();
 demonstrateProducerConsumer();
 demonstrateBarrierSynchronization();
 }

 /**
 * Example 1: Critical Section with Intrinsic Lock (Monitor)
 * Java's synchronized keyword implements the monitor pattern.
 * Only one thread can execute synchronized code on the same object.
 */
 static class Counter {
 private int value = 0;
 private final Object lock = new Object(); // Explicit lock object

 // Method-level synchronized - whole method is critical section
 public synchronized void increment() {
 int temp = value;
 try {
 Thread.sleep(1); // Simulate processing
 } catch (InterruptedException e) {}
 value = temp + 1;
 }

 // Block-level synchronized - only this block is critical section
 public void incrementBlock() {
 synchronized (lock) {
 int temp = value;
 try {
 Thread.sleep(1);
 } catch (InterruptedException e) {}
 value = temp + 1;
 }
 }

 public int getValue() {
 synchronized (lock) {
 return value;
 }
 }
 }

 static void demonstrateCriticalSection() throws InterruptedException {
 System.out.println("=== Critical Section with Monitor (synchronized) ===");

 Counter counter = new Counter();
 int numThreads = 5;
 int iterations = 1000;

 Thread[] threads = new Thread[numThreads];

 for (int i = 0; i < numThreads; i++) {
 threads[i] = new Thread(() -> {
 for (int j = 0; j < iterations; j++) {
 counter.incrementBlock();
 }
 });
 threads[i].start();
 }

 for (Thread t : threads) {
 t.join();
 }

 int expected = numThreads * iterations;
 System.out.println("Expected: " + expected + ", Actual: " + counter.getValue());
 System.out.println("Correct: " + (counter.getValue() == expected) + "\n");
 }

 /**
 * Example 2: Binary Semaphore Implementation using wait/notify
 * Demonstrates classic monitor pattern - lock + condition variables
 */
 static class BinarySemaphore {
 private int value;
 private final Object monitor = new Object();

 public BinarySemaphore(int initial) {
 this.value = initial;
 }

 // P operation (wait) - acquire
 public void wait_() throws InterruptedException {
 synchronized (monitor) {
 while (value == 0) {
 monitor.wait(); // Block until signaled
 }
 value = 0;
 }
 }

 // V operation (signal) - release
 public void signal() {
 synchronized (monitor) {
 value = 1;
 monitor.notify(); // Wake up one waiting thread
 }
 }
 }

 static void demonstrateBinarySemaphore() throws InterruptedException {
 System.out.println("=== Binary Semaphore with wait/notify ===");

 BinarySemaphore semaphore = new BinarySemaphore(1);
 CountDownLatch latch = new CountDownLatch(3);

 for (int i = 0; i < 3; i++) {
 final int threadId = i;
 new Thread(() -> {
 try {
 System.out.println("Thread " + threadId + " trying to acquire...");
 semaphore.wait_();
 System.out.println("Thread " + threadId + " ENTERED critical section");
 Thread.sleep(500);
 System.out.println("Thread " + threadId + " EXITING critical section");
 semaphore.signal();
 } catch (InterruptedException e) {}
 latch.countDown();
 }).start();
 }

 latch.await();
 System.out.println("Binary semaphore demo complete\n");
 }

 /**
 * Example 3: Producer-Consumer with BlockingQueue
 * Java provides high-level concurrency utilities that handle
 * counting semaphores internally.
 */
 static void demonstrateProducerConsumer() throws InterruptedException {
 System.out.println("=== Producer-Consumer with BlockingQueue ===");

 // BlockingQueue is essentially a bounded buffer with built-in semaphores
 BlockingQueue<Integer> buffer = new ArrayBlockingQueue<>(5);

 int numItems = 10;
 CountDownLatch doneLatch = new CountDownLatch(2);

 // Producer thread
 Thread producer = new Thread(() -> {
 try {
 for (int i = 0; i < numItems; i++) {
 int item = i * 100;
 buffer.put(item); // Automatically handles empty_slots semaphore
 System.out.println("Produced: " + item);
 Thread.sleep(100);
 }
 } catch (InterruptedException e) {}
 doneLatch.countDown();
 });

 // Consumer thread
 Thread consumer = new Thread(() -> {
 try {
 for (int i = 0; i < numItems; i++) {
 Integer item = buffer.take(); // Automatically handles full_slots semaphore
 System.out.println("Consumed: " + item);
 Thread.sleep(150);
 }
 } catch (InterruptedException e) {}
 doneLatch.countDown();
 });

 producer.start();
 consumer.start();
 doneLatch.await();
 System.out.println("Producer-Consumer complete\n");
 }

 /**
 * Example 4: Barrier Synchronization
 * Demonstrates bounded waiting - all threads must reach barrier
 * before any can proceed.
 */
 static void demonstrateBarrierSynchronization() throws InterruptedException {
 System.out.println("=== Barrier Synchronization (Bounded Waiting) ===");

 int numThreads = 4;
 CountDownLatch barrier = new CountDownLatch(numThreads);
 AtomicInteger completedCount = new AtomicInteger(0);

 for (int i = 0; i < numThreads; i++) {
 final int threadId = i;
 new Thread(() -> {
 System.out.println("Thread " + threadId + " started phase 1");
 // Do some work
 try { Thread.sleep((long)(Math.random() * 500)); } catch (Exception e) {}

 System.out.println("Thread " + threadId + " reached barrier");
 barrier.countDown(); // Signal arrival at barrier

 try {
 barrier.await(); // Wait for all threads
 } catch (InterruptedException e) {}

 // All threads synchronize here - bounded waiting satisfied
 System.out.println("Thread " + threadId + " proceeding after barrier");
 completedCount.incrementAndGet();
 }).start();
 }

 // Wait for all to complete
 while (completedCount.get() < numThreads) {
 Thread.sleep(100);
 }

 System.out.println("All threads synchronized - bounded waiting demonstrated\n");
 }
}

/**
 * Notes on Java Synchronization:
 * 
 * 1. MONITOR PATTERN: Java's synchronized keyword implements monitors.
 * Every object has an intrinsic lock and condition variable (wait/notify).
 * Only one thread can hold the monitor at a time.
 * 
 * 2. MUTUAL EXCLUSION: synchronized blocks provide mutual exclusion,
 * satisfying the "mutual exclusion" requirement of critical section.
 * 
 * 3. PROGRESS: wait() releases the lock, allowing other threads to proceed.
 * notify() wakes a waiting thread, ensuring progress.
 * 
 * 4. BOUNDED WAITING: CountDownLatch and CyclicBarrier ensure all threads
 * synchronize, preventing starvation.
 * 
 * 5. HIGH-LEVEL UTILITIES: BlockingQueue combines counting semaphores
 * and mutex into a thread-safe producer-consumer buffer.
 */
